search:angular-ngrx-store-redis-persist:.content:
- **CLI Commands**:
  - `ng new my-angular-app`
  - `ng generate store feature-name`

- **Latest Versions**:
  - Angular: 16.x
  - NgRx: 15.x

- **Key Config Options**:
  - Store Configuration in `app.module.ts`:
    ```typescript
    import { StoreModule } from '@ngrx/store';
    import { reducers } from './reducers';

    @NgModule({
      imports: [
        StoreModule.forRoot(reducers)
      ]
    })
    export class AppModule { }
    ```
  - Feature Reducers:
    ```typescript
    import { createReducer, on } from '@ngrx/store';
    import * as actions from '../actions/feature.actions';

    const initialState = {
      data: null,
      loading: false,
      error: null
    };

    export const featureReducer = createReducer(
      initialState,
      on(actions.loadFeature, state => ({ ...state, loading: true })),
      on(actions.featureLoaded, (state, { payload }) => ({ ...state, data: payload, loading: false })),
      on(actions.featureLoadFailed, (state, { error }) => ({ ...state, error, loading: false }))
    );
    ```
  - Effects for Asynchronous Actions:
    ```typescript
    import { Injectable } from '@angular/core';
    import { Actions, createEffect, ofType } from '@ngrx/effects';
    import * as actions from '../actions/feature.actions';
    import { switchMap, map, catchError } from 'rxjs/operators';
    import { of } from 'rxjs';

    @Injectable()
    export class FeatureEffects {
      loadFeature$ = createEffect(() =>
        this.actions$.pipe(
          ofType(actions.loadFeature),
          switchMap(() => 
            this.featureService.getFeature().pipe(
              map(data => actions.featureLoaded({ payload: data })),
              catchError(error => of(actions.featureLoadFailed({ error })))
            )
          )
        )
      );

      constructor(private actions$: Actions, private featureService: FeatureService) {}
    }
    ```
